  1→import { RecordId, type Surreal } from "surrealdb";
  2→import type {
  3→  ContextPacket,
  4→  DecisionContext,
  5→  TaskContext,
  6→  QuestionContext,
  7→  ObservationContext,
  8→  ActiveSessionContext,
  9→  TaskScopeContext,
 10→  RecentChangeContext,
 11→} from "./types";
 12→import { toRawId } from "./id-format";
 13→
 14→type ProjectRow = {
 15→  id: RecordId<"project", string>;
 16→  name: string;
