102→/** Build a broad project context packet (all decisions, tasks, questions for a project) */
103→export async function buildProjectContext(input: {
104→  surreal: Surreal;
105→  workspaceRecord: RecordId<"workspace", string>;
106→  workspaceName: string;
107→  projectRecord: RecordId<"project", string>;
108→  taskId?: string;
109→  since?: string;
110→  excludeSessionId?: string;
111→}): Promise<ContextPacket> {
112→  const { surreal, workspaceRecord, workspaceName, projectRecord, taskId } = input;
113→
114→  // Load project details
115→  const project = await surreal.select<ProjectRow>(projectRecord);
116→  if (!project) {
117→    throw new Error(`project not found: ${projectRecord.id}`);
118→  }
119→
120→  // Load project-scoped entities in parallel
121→  const projectEntitiesQuery = `
122→    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
123→
124→    SELECT id, summary, status, rationale, decided_at, category, priority
125→    FROM decision
126→    WHERE workspace = $workspace AND id IN $project_entity_ids
127→    ORDER BY created_at DESC LIMIT 50;
128→
129→    SELECT id, title, status, priority, category, description, source_session
130→    FROM task
131→    WHERE workspace = $workspace AND id IN $project_entity_ids
132→    ORDER BY created_at DESC LIMIT 50;
133→
134→    SELECT id, text, status, context, priority
135→    FROM question
136→    WHERE workspace = $workspace AND id IN $project_entity_ids
137→    ORDER BY created_at DESC LIMIT 30;
138→
139→    SELECT id, text, severity, status, category, observation_type
140→    FROM observation
141→    WHERE workspace = $workspace AND status IN ["open", "acknowledged"]
142→    ORDER BY created_at DESC LIMIT 20;
143→  `;
144→
145→  const results = await surreal
146→    .query<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[]]>(projectEntitiesQuery, {
147→      project: projectRecord,
148→      workspace: workspaceRecord,
149→    })
150→    .collect<[null, DecisionRow[], TaskRow[], QuestionRow[], ObservationRow[]]>();
151→
152→  const [, decisionRows, taskRows, questionRows, observationRows] = results;
153→
154→  // Categorize decisions by status
155→  const confirmed: DecisionContext[] = [];
156→  const provisional: DecisionContext[] = [];
157→  const contested: DecisionContext[] = [];
158→
159→  for (const d of decisionRows) {
160→    const ctx: DecisionContext = {
161→      id: toRawId(d.id),
162→      summary: d.summary,
163→      status: d.status,
164→      ...(d.rationale ? { rationale: d.rationale } : {}),
165→      ...(d.decided_at ? { decided_at: toIso(d.decided_at) } : {}),
166→      ...(d.category ? { category: d.category } : {}),
167→      ...(d.priority ? { priority: d.priority } : {}),
168→    };
169→
170→    if (d.status === "contested") {
171→      contested.push(ctx);
172→    } else if (d.status === "provisional" || d.status === "inferred") {
173→      provisional.push(ctx);
174→    } else if (d.status === "confirmed") {
175→      confirmed.push(ctx);
176→    }
177→  }
178→
179→  // Map tasks
180→  const activeTasks: TaskContext[] = taskRows
181→    .filter((t) => t.status !== "done" && t.status !== "completed")
182→    .map((t) => ({
183→      id: toRawId(t.id),
184→      title: t.title,
185→      status: t.status,
186→      ...(t.priority ? { priority: t.priority } : {}),
187→      ...(t.category ? { category: t.category } : {}),
188→      ...(t.source_session ? { source_session: toRawId(t.source_session) } : {}),
189→    }));
190→
191→  // Map questions
192→  const openQuestions: QuestionContext[] = questionRows
193→    .filter((q) => q.status !== "answered" && q.status !== "resolved")
194→    .map((q) => ({
195→      id: toRawId(q.id),
196→      text: q.text,
197→      status: q.status,
198→      ...(q.context ? { context: q.context } : {}),
199→      ...(q.priority ? { priority: q.priority } : {}),
200→    }));
201→
202→  // Map observations
203→  const observations: ObservationContext[] = observationRows.map((o) => ({
204→    id: toRawId(o.id),
205→    text: o.text,
206→    severity: o.severity,
207→    status: o.status,
208→    ...(o.category ? { category: o.category } : {}),
209→    ...(o.observation_type ? { observation_type: o.observation_type } : {}),
210→  }));
211→
212→  // Load active sessions on the same project (exclude self)
213→  const activeSessions = await loadActiveSessions(
214→    surreal,
215→    workspaceRecord,
216→    projectRecord,
217→    input.excludeSessionId,
218→  );
219→
220→  // Build recent changes if `since` provided
221→  const recentChanges: RecentChangeContext[] = input.since
222→    ? await loadRecentChanges(surreal, workspaceRecord, projectRecord, input.since)
223→    : [];
224→
225→  // Build task scope if taskId provided
226→  let taskScope: TaskScopeContext | undefined;
227→  if (taskId) {
228→    taskScope = await buildTaskScope(surreal, workspaceRecord, projectRecord, taskId);
229→  }
230→
231→  return {
232→    workspace: { id: workspaceRecord.id as string, name: workspaceName },
233→    project: {
234→      id: projectRecord.id as string,
235→      name: project.name,
236→      status: project.status,
237→      ...(project.description ? { description: project.description } : {}),
238→    },
239→    ...(taskScope ? { task_scope: taskScope } : {}),
240→    decisions: { confirmed, provisional, contested },
241→    active_tasks: activeTasks,
242→    open_questions: openQuestions,
243→    recent_changes: recentChanges,
244→    observations,
245→    active_sessions: activeSessions,
246→  };
247→}
248→
249→/** Build task-scoped context: subtasks, parent feature, siblings, dependencies, related sessions */
250→async function buildTaskScope(
251→  surreal: Surreal,
252→  workspaceRecord: RecordId<"workspace", string>,
253→  _projectRecord: RecordId<"project", string>,
254→  taskId: string,
255→): Promise<TaskScopeContext> {
256→  const taskRecord = new RecordId("task", taskId);
257→  const task = await surreal.select<TaskRow & { workspace: RecordId<"workspace", string> }>(taskRecord);
258→  if (!task) {
259→    throw new Error(`task not found: ${taskId}`);
260→  }
261→  if ((task.workspace.id as string) !== (workspaceRecord.id as string)) {
262→    throw new Error(`task not in workspace: ${taskId}`);
263→  }
264→
265→  // Load subtasks, parent feature, dependencies, and related sessions in parallel
266→  const taskScopeQuery = `
267→    -- Subtasks of this task
268→    SELECT id, title, status
269→    FROM task
270→    WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $task)
271→    ORDER BY created_at ASC;
272→
273→    -- Parent feature (via has_task edge)
274→    SELECT id, name, description
275→    FROM feature
276→    WHERE id IN (SELECT VALUE \`in\` FROM has_task WHERE out = $task)
277→    LIMIT 1;
278→
279→    -- Dependencies (tasks this task depends on)
280→    SELECT id, title, status
281→    FROM task
282→    WHERE id IN (SELECT VALUE out FROM depends_on WHERE \`in\` = $task);
283→
284→    -- Recent agent sessions that touched this task
285→    SELECT id, agent, ended_at, summary
286→    FROM agent_session
287→    WHERE task_id = $task AND ended_at != NONE
288→    ORDER BY ended_at DESC LIMIT 5;
289→  `;
290→
291→  const results = await surreal
292→    .query<[SubtaskRow[], FeatureRow[], DependencyRow[], AgentSessionRow[]]>(taskScopeQuery, {
293→      task: taskRecord,
294→    })
295→    .collect<[SubtaskRow[], FeatureRow[], DependencyRow[], AgentSessionRow[]]>();
296→
297→  const [subtaskRows, featureRows, dependencyRows, sessionRows] = results;
298→
299→  const parentFeature = featureRows.length > 0
300→    ? {
301→        id: toRawId(featureRows[0].id),
302→        name: featureRows[0].name,
303→        ...(featureRows[0].description ? { description: featureRows[0].description } : {}),
304→      }
305→    : undefined;
306→
307→  // Load sibling tasks (other tasks under same feature)
308→  let siblingTasks: { id: string; title: string; status: string; source_session?: string }[] = [];
309→  if (parentFeature && featureRows.length > 0) {
310→    const [siblingRows] = await surreal
311→      .query<[TaskRow[]]>(
312→        `SELECT id, title, status, source_session FROM task
313→         WHERE id IN (SELECT VALUE out FROM has_task WHERE \`in\` = $feature)
314→           AND id != $task
315→         ORDER BY created_at ASC LIMIT 20;`,
316→        { feature: featureRows[0].id, task: taskRecord },
317→      )
318→      .collect<[TaskRow[]]>();
319→
320→    siblingTasks = siblingRows.map((t) => ({
321→      id: toRawId(t.id),
322→      title: t.title,
323→      status: t.status,
324→      ...(t.source_session ? { source_session: toRawId(t.source_session) } : {}),
325→    }));
326→  }
327→
328→  return {
329→    task: {
330→      id: toRawId(task.id),
331→      title: task.title,
332→      ...(task.description ? { description: task.description } : {}),
333→      status: task.status,
334→      ...(task.category ? { category: task.category } : {}),
335→    },
336→    subtasks: subtaskRows.map((s) => ({
337→      id: toRawId(s.id),
338→      title: s.title,
339→      status: s.status,
340→    })),
341→    parent_feature: parentFeature,
342→    sibling_tasks: siblingTasks,
343→    dependencies: dependencyRows.map((d) => ({
344→      id: toRawId(d.id),
345→      title: d.title,
346→      status: d.status,
347→    })),
348→    related_sessions: sessionRows.map((s) => ({
349→      id: toRawId(s.id),
350→      agent: s.agent,
351→      ended_at: toIso(s.ended_at),
352→      summary: s.summary ?? "",
353→    })),
354→  };
355→}
356→
357→/** Load active agent sessions on the same project, with their provisional decisions and observations */
358→async function loadActiveSessions(
359→  surreal: Surreal,
360→  workspaceRecord: RecordId<"workspace", string>,
361→  projectRecord: RecordId<"project", string>,
362→  excludeSessionId?: string,
363→): Promise<ActiveSessionContext[]> {
364→  const excludeRecord = excludeSessionId
365→    ? new RecordId("agent_session", excludeSessionId)
366→    : new RecordId("agent_session", "__none__");
367→
368→  const [sessionRows] = await surreal
369→    .query<[ActiveAgentSessionRow[]]>(
370→      `SELECT id, agent, started_at, task_id
371→       FROM agent_session
372→       WHERE workspace = $workspace AND project = $project AND ended_at = NONE AND id != $exclude
373→       ORDER BY started_at DESC LIMIT 10;`,
374→      { workspace: workspaceRecord, project: projectRecord, exclude: excludeRecord },
375→    )
376→    .collect<[ActiveAgentSessionRow[]]>();
377→
378→  if (sessionRows.length === 0) return [];
379→
380→  const sessionIds = sessionRows.map((s) => s.id);
381→
382→  // Load open observations for all active sessions in one query
383→  const [observationRows] = await surreal
384→    .query<[SessionObservationRow[]]>(
385→      `SELECT id, text, severity, source_session FROM observation
386→       WHERE source_session IN $sessions
387→         AND status IN ["open", "acknowledged"];`,
388→      { sessions: sessionIds },
389→    )
390→    .collect<[SessionObservationRow[]]>();
391→
392→  // Load task titles for task-scoped sessions
393→  const taskIds = sessionRows
394→    .filter((s) => s.task_id)
395→    .map((s) => s.task_id!);
396→
397→  let taskTitles: Map<string, string> = new Map();
398→  if (taskIds.length > 0) {
399→    const [taskRows] = await surreal
400→      .query<[Array<{ id: RecordId<"task", string>; title: string }>]>(
401→        `SELECT id, title FROM task WHERE id IN $tasks;`,
402→        { tasks: taskIds },
403→      )
404→      .collect<[Array<{ id: RecordId<"task", string>; title: string }>]>();
405→    taskTitles = new Map(taskRows.map((t) => [toRawId(t.id), t.title]));
406→  }
407→
408→  // Index observations by session
409→  const obsBySession = new Map<string, Array<{ id: string; text: string; severity: string }>>();
410→  for (const o of observationRows) {
411→    const sessionKey = toRawId(o.source_session);
412→    const arr = obsBySession.get(sessionKey) ?? [];
413→    arr.push({ id: toRawId(o.id), text: o.text, severity: o.severity });
414→    obsBySession.set(sessionKey, arr);
415→  }
416→
417→  // Index provisional decisions by session (avoid cross-session misattribution)
418→  const decisionsBySession = new Map<string, Array<{ id: string; summary: string }>>();
419→  for (const session of sessionRows) {
420→    const sessionKey = toRawId(session.id);
421→    const [decisionRows] = await surreal
422→      .query<[Array<{ id: RecordId<"decision", string>; summary: string }>]>(
423→        `SELECT id, summary FROM decision
424→         WHERE id IN (SELECT VALUE out FROM produced WHERE \`in\` = $session)
425→           AND status = "provisional";`,
426→        { session: session.id },
427→      )
428→      .collect<[Array<{ id: RecordId<"decision", string>; summary: string }>]>();
429→
430→    decisionsBySession.set(
431→      sessionKey,
432→      decisionRows.map((d) => ({ id: toRawId(d.id), summary: d.summary })),
433→    );
434→  }
435→
436→  return sessionRows.map((s) => {
437→    const sessionKey = toRawId(s.id);
438→    const taskId = s.task_id ? toRawId(s.task_id) : undefined;
439→    return {
440→      id: sessionKey,
441→      agent: s.agent,
442→      started_at: toIso(s.started_at),
443→      ...(taskId && taskTitles.has(taskId)
444→        ? { task: { id: taskId, title: taskTitles.get(taskId)! } }
445→        : {}),
446→      provisional_decisions: decisionsBySession.get(sessionKey) ?? [],
447→      observations: obsBySession.get(sessionKey) ?? [],
448→    };
449→  });
450→}
451→
452→/** Load entities changed since a timestamp for the recent_changes field */
453→async function loadRecentChanges(
454→  surreal: Surreal,
455→  workspaceRecord: RecordId<"workspace", string>,
456→  projectRecord: RecordId<"project", string>,
457→  since: string,
458→): Promise<RecentChangeContext[]> {
459→  const sinceDate = new Date(since);
460→
461→  const query = `
462→    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
463→
464→    LET $recent_decisions = SELECT "decision" AS entity_type, summary AS entity_name, status AS change_type, updated_at AS changed_at
465→    FROM decision
466→    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
467→    ORDER BY updated_at DESC LIMIT 20;
468→
469→    LET $recent_tasks = SELECT "task" AS entity_type, title AS entity_name, status AS change_type, updated_at AS changed_at
470→    FROM task
471→    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
472→    ORDER BY updated_at DESC LIMIT 20;
473→
474→    LET $recent_questions = SELECT "question" AS entity_type, text AS entity_name, status AS change_type, updated_at AS changed_at
475→    FROM question
476→    WHERE workspace = $workspace AND id IN $project_entity_ids AND updated_at > $since
477→    ORDER BY updated_at DESC LIMIT 20;
478→
479→    LET $recent_observations = SELECT "observation" AS entity_type, text AS entity_name, severity AS change_type, updated_at AS changed_at
480→    FROM observation
481→    WHERE workspace = $workspace AND updated_at > $since
482→    ORDER BY updated_at DESC LIMIT 20;
483→
484→    RETURN array::flatten([$recent_decisions, $recent_tasks, $recent_questions, $recent_observations]);
485→  `;
486→
487→  const results = await surreal
488→    .query<[null, null, null, null, null, RecentChangeRow[]]>(query, {
489→      project: projectRecord,
490→      workspace: workspaceRecord,
491→      since: sinceDate,
492→    })
493→    .collect<[null, null, null, null, null, RecentChangeRow[]]>();
494→
495→  const rows = results[5] ?? [];
496→
497→  return rows.map((r) => ({
498→    entity_type: r.entity_type,
499→    entity_name: r.entity_name,
500→    change_type: r.change_type,
501→    changed_at: toIso(r.changed_at),
502→  }));
503→}
504→
505→type RecentChangeRow = {
506→  entity_type: string;
507→  entity_name: string;
508→  change_type: string;
509→  changed_at: Date | string;
510→};
