333→function formatContextPacket(packet: unknown): string {
334→  const p = packet as Record<string, unknown>;
335→  const lines: string[] = [];
336→
337→  lines.push("# Brain Knowledge Graph Context\n");
338→
339→  // Workspace & project
340→  const ws = p.workspace as { id: string; name: string } | undefined;
341→  const proj = p.project as { id: string; name: string; status: string; description?: string } | undefined;
342→  if (ws) lines.push(`Workspace: ${ws.name}`);
343→  if (proj) {
344→    lines.push(`Project: ${proj.name} (${proj.status})`);
345→    if (proj.description) lines.push(`Description: ${proj.description}`);
346→  }
347→  lines.push("");
348→
349→  // Task scope
350→  const taskScope = p.task_scope as Record<string, unknown> | undefined;
351→  if (taskScope) {
352→    const task = taskScope.task as { id: string; title: string; status: string; description?: string };
353→    lines.push(`## Current Task: ${task.title} [${task.status}]`);
354→    if (task.description) lines.push(task.description);
355→
356→    const subtasks = taskScope.subtasks as Array<{ id: string; title: string; status: string }>;
357→    if (subtasks?.length) {
358→      lines.push("\nSubtasks:");
359→      for (const s of subtasks) lines.push(`  - [${s.status}] ${s.title}`);
360→    }
361→
362→    const siblings = taskScope.sibling_tasks as Array<{ id: string; title: string; status: string }>;
363→    if (siblings?.length) {
364→      lines.push("\nSibling tasks:");
365→      for (const s of siblings) lines.push(`  - [${s.status}] ${s.title}`);
366→    }
367→    lines.push("");
368→  }
369→
370→  // Decisions
371→  const decisions = p.decisions as { confirmed: unknown[]; provisional: unknown[]; contested: unknown[] } | undefined;
372→  if (decisions) {
373→    if (decisions.contested.length > 0) {
374→      lines.push("## CONTESTED DECISIONS (conflicts — do not proceed without human input)");
375→      for (const d of decisions.contested as Array<{ summary: string; rationale?: string }>) {
376→        lines.push(`  - ${d.summary}${d.rationale ? ` — ${d.rationale}` : ""}`);
377→      }
378→      lines.push("");
379→    }
380→
381→    if (decisions.confirmed.length > 0) {
382→      lines.push("## Confirmed Decisions (follow these)");
383→      for (const d of decisions.confirmed as Array<{ summary: string }>) {
384→        lines.push(`  - ${d.summary}`);
385→      }
386→      lines.push("");
387→    }
388→
389→    if (decisions.provisional.length > 0) {
390→      lines.push("## Provisional Decisions (follow but flag for review)");
391→      for (const d of decisions.provisional as Array<{ summary: string }>) {
392→        lines.push(`  - ${d.summary}`);
393→      }
394→      lines.push("");
395→    }
396→  }
397→
398→  // Active tasks
399→  const tasks = p.active_tasks as Array<{ title: string; status: string; priority?: string }> | undefined;
400→  if (tasks?.length) {
401→    lines.push("## Active Tasks");
402→    for (const t of tasks) {
403→      lines.push(`  - [${t.status}]${t.priority ? ` (${t.priority})` : ""} ${t.title}`);
404→    }
405→    lines.push("");
406→  }
407→
408→  // Open questions
409→  const questions = p.open_questions as Array<{ text: string; status: string }> | undefined;
410→  if (questions?.length) {
411→    lines.push("## Open Questions");
412→    for (const q of questions) {
413→      lines.push(`  - [${q.status}] ${q.text}`);
414→    }
415→    lines.push("");
416→  }
417→
418→  // Recent changes
419→  const changes = p.recent_changes as Array<{ entity_type: string; entity_name: string; change_type: string; changed_at: string }> | undefined;
420→  if (changes?.length) {
421→    lines.push("## Recent Changes");
422→    for (const c of changes) {
423→      lines.push(`  - [${c.entity_type}] ${c.entity_name} — ${c.change_type}`);
424→    }
425→    lines.push("");
426→  }
