 380→      }, 200);
 381→    }
 382→
 383→    const projectRecord = body.context?.project
 384→      ? await resolveWorkspaceProjectRecord({ surreal, workspaceRecord: auth.workspaceRecord, projectInput: body.context.project })
 385→      : undefined;
 386→
 387→    const candidates = await searchEntitiesByEmbedding({
 388→      surreal,
 389→      workspaceRecord: auth.workspaceRecord,
 390→      queryEmbedding,
 391→      kinds: ["decision"],
 392→      ...(projectRecord ? { projectRecord } : {}),
 393→      limit: 10,
 394→    });
 395→
 396→    // Check if any existing decision resolves the question
 397→    const questionTokens = normalizeTokens(body.question);
 398→    const relevant = candidates.filter((c) => {
 399→      const tokens = normalizeTokens(c.name);
 400→      return c.score >= 0.78 && hasTokenOverlap(questionTokens, tokens);
 401→    });
 402→
 403→    if (relevant.length > 0) {
 404→      const best = relevant[0];
 405→      return jsonResponse({
 406→        decision: best.name,
 407→        confidence: Number(best.score.toFixed(4)),
 408→        status: best.status ?? "unknown",
 409→        rationale: `Existing ${best.status} decision found with ${(best.score * 100).toFixed(1)}% similarity`,
 410→        sources: relevant.map((r) => ({ id: `${r.kind}:${r.id}`, name: r.name, score: Number(r.score.toFixed(4)) })),
 411→      }, 200);
 412→    }
 413→
 414→    return jsonResponse({
 415→      decision: undefined,
 416→      confidence: 0,
 417→      status: "unresolved",
 418→      rationale: "No existing decision found that resolves this question",
 419→      sources: candidates.slice(0, 5).map((c) => ({
 420→        id: `${c.kind}:${c.id}`,
 421→        name: c.name,
 422→        score: Number(c.score.toFixed(4)),
 423→      })),
 424→    }, 200);
 425→  }
