 427→  /** POST /api/mcp/:workspaceId/constraints/check — Check proposed action */
 428→  async function handleCheckConstraints(workspaceId: string, request: Request): Promise<Response> {
 429→    const auth = await requireAuth(request, workspaceId);
 430→    if (auth instanceof Response) return auth;
 431→
 432→    const body = await parseJsonBody<{ proposed_action: string; project?: string }>(request);
 433→    if (body instanceof Response) return body;
 434→    if (!body.proposed_action) return jsonError("proposed_action is required", 400);
 435→
 436→    const queryEmbedding = await createEmbeddingVector(
 437→      deps.embeddingModel,
 438→      body.proposed_action,
 439→      config.embeddingDimension,
 440→    );
 441→
 442→    if (!queryEmbedding) {
 443→      return jsonResponse({ hard_conflicts: [], soft_tensions: [], supporting: [], proceed: true }, 200);
 444→    }
 445→
 446→    const projectRecord = body.project
 447→      ? await resolveWorkspaceProjectRecord({ surreal, workspaceRecord: auth.workspaceRecord, projectInput: body.project })
 448→      : undefined;
 449→
 450→    const candidates = await listDecisionConstraintCandidates({
 451→      surreal,
 452→      workspaceRecord: auth.workspaceRecord,
 453→      queryEmbedding,
 454→      ...(projectRecord ? { projectRecord } : {}),
 455→      limit: 14,
 456→    });
 457→
 458→    const actionTokens = normalizeTokens(body.proposed_action);
 459→    const hardConflicts: Array<{ id: string; name: string; score: number; reason: string }> = [];
 460→    const softTensions: Array<{ id: string; name: string; score: number; reason: string }> = [];
 461→    const supporting: Array<{ id: string; name: string; score: number; reason: string }> = [];
 462→
 463→    for (const candidate of candidates) {
 464→      const candidateTokens = normalizeTokens(candidate.name);
 465→      const overlap = hasTokenOverlap(actionTokens, candidateTokens);
 466→      const status = candidate.status?.toLowerCase();
 467→
 468→      if (candidate.kind === "decision" && overlap && (status === "contested" || status === "superseded")) {
 469→        hardConflicts.push({
 470→          id: `${candidate.kind}:${candidate.id}`,
 471→          name: candidate.name,
 472→          score: Number(candidate.score.toFixed(4)),
 473→          reason: `Decision is marked ${status}.`,
 474→        });
 475→        continue;
 476→      }
 477→
 478→      if (candidate.kind === "decision" && candidate.score >= 0.86 && overlap) {
 479→        supporting.push({
 480→          id: `${candidate.kind}:${candidate.id}`,
 481→          name: candidate.name,
 482→          score: Number(candidate.score.toFixed(4)),
 483→          reason: "High-similarity decision aligns with proposed action.",
 484→        });
 485→        continue;
 486→      }
 487→
 488→      if (candidate.score >= 0.72) {
 489→        softTensions.push({
 490→          id: `${candidate.kind}:${candidate.id}`,
 491→          name: candidate.name,
 492→          score: Number(candidate.score.toFixed(4)),
 493→          reason: overlap
 494→            ? "Related decision/question may require consistency checks."
 495→            : "Semantically related context may be affected.",
 496→        });
 497→      }
 498→    }
 499→
 500→    return jsonResponse({ hard_conflicts: hardConflicts, soft_tensions: softTensions, supporting, proceed: hardConflicts.length === 0 }, 200);
 501→  }
