 718→  /** POST /api/mcp/:workspaceId/observations — Log a codebase observation */
 719→  async function handleLogObservation(workspaceId: string, request: Request): Promise<Response> {
 720→    const auth = await requireAuth(request, workspaceId);
 721→    if (auth instanceof Response) return auth;
 722→
 723→    const body = await parseJsonBody<{
 724→      text: string;
 725→      category: string;
 726→      severity: string;
 727→      target?: string;
 728→      session_id?: string;
 729→    }>(request);
 730→    if (body instanceof Response) return body;
 731→    if (!body.text) return jsonError("text is required", 400);
 732→    if (!body.category) return jsonError("category is required", 400);
 733→    if (!body.severity) return jsonError("severity is required", 400);
 734→
 735→    if (!OBSERVATION_TYPES.includes(body.category as ObservationType)) {
 736→      return jsonError(`invalid category: must be one of ${OBSERVATION_TYPES.join(", ")}`, 400);
 737→    }
 738→
 739→    const validSeverities = ["info", "warning", "conflict"];
 740→    if (!validSeverities.includes(body.severity)) {
 741→      return jsonError("invalid severity: must be info, warning, or conflict", 400);
 742→    }
 743→
 744→    type ObserveTable = "project" | "feature" | "task" | "decision" | "question";
 745→    let relatedRecord: RecordId<ObserveTable, string> | undefined;
 746→    if (body.target) {
 747→      try {
 748→        relatedRecord = parseRecordIdString(body.target, ["project", "feature", "task", "decision", "question"] as const);
 749→      } catch {
 750→        return jsonError(`invalid target entity: ${body.target}`, 400);
 751→      }
 752→      const scopedTargetError = await requireScopedRecord(relatedRecord, auth.workspaceRecord, "target");
 753→      if (scopedTargetError) return scopedTargetError;
 754→    }
 755→
 756→    const embedding = await createEmbeddingVector(
 757→      deps.embeddingModel,
 758→      body.text,
 759→      config.embeddingDimension,
 760→    );
 761→
 762→    let sourceSessionRecord: RecordId<"agent_session", string> | undefined;
 763→    if (body.session_id) {
 764→      try {
 765→        const sessionId = requireRawId(body.session_id, "session_id");
 766→        sourceSessionRecord = new RecordId("agent_session", sessionId);
 767→      } catch (error) {
 768→        return jsonError(error instanceof Error ? error.message : "invalid session_id", 400);
 769→      }
 770→    }
 771→    if (sourceSessionRecord) {
 772→      const scopedSessionError = await requireScopedRecord(sourceSessionRecord, auth.workspaceRecord, "session");
 773→      if (scopedSessionError) return scopedSessionError;
 774→    }
 775→
 776→    const now = new Date();
 777→
 778→    const observationRecord = await createObservation({
 779→      surreal,
 780→      workspaceRecord: auth.workspaceRecord,
 781→      text: body.text,
 782→      severity: body.severity as ObservationSeverity,
 783→      observationType: body.category as ObservationType,
 784→      sourceAgent: "code-agent",
 785→      now,
 786→      ...(sourceSessionRecord ? { sourceSessionRecord } : {}),
 787→      ...(relatedRecord ? { relatedRecord } : {}),
 788→      ...(embedding ? { embedding } : {}),
 789→    });
 790→
 791→    // Create observed_in edge: observation -> agent_session
 792→    if (sourceSessionRecord) {
 793→      await surreal
 794→        .relate(observationRecord, new RecordId("observed_in", crypto.randomUUID()), sourceSessionRecord, {
 795→          added_at: now,
 796→        })
 797→        .output("after");
 798→    }
 799→
 800→    logInfo("mcp.observation.created", "Observation logged via MCP", {
 801→      workspaceId,
 802→      observationId: observationRecord.id as string,
 803→      observationType: body.category,
 804→      severity: body.severity,
 805→    });
 806→
 807→    return jsonResponse({
 808→      observation_id: observationRecord.id as string,
 809→      severity: body.severity,
 810→      status: "open",
 811→    }, 201);
 812→  }
