225→
226→  // 3. Resolve suggests_for target to find linked project
227→  const [suggestsForRows] = await input.surreal
228→    .query<[Array<{ out: RecordId<string, string> }>]>(
229→      "SELECT out FROM suggests_for WHERE in = $suggestion;",
230→      { suggestion: input.suggestionRecord },
231→    )
232→    .collect<[Array<{ out: RecordId<string, string> }>]>();
233→  const linkedProject = suggestsForRows.find((r) => r.out.table.name === "project");
234→
235→  // 4. Create target entity
236→  let targetRecord: RecordId<string, string>;
237→
238→  if (input.targetKind === "task") {
239→    const taskId = randomUUID();
