  DecisionContext,
  TaskContext,
  QuestionContext,
  ObservationContext,
  SuggestionContext,
  ActiveSessionContext,
  TaskScopeContext,
  RecentChangeContext,
} from "./types";
import { toRawId } from "./id-format";

type ProjectRow = {
  id: RecordId<"project", string>;
  name: string;
  status: string;
