};

type TaskRow = {
  id: RecordId<"task", string>;
  title: string;
  status: string;
  priority?: string;
  category?: string;
  description?: string;
  source_session?: RecordId<"agent_session", string>;
};

type QuestionRow = {
  id: RecordId<"question", string>;
