494→DEFINE FUNCTION fn::entity_search_project($q: string, $limit: int, $workspace: record<workspace>, $project: record<project>) {
495→  LET $query = string::lowercase(string::trim($q));
496→  LET $safe_limit = math::min([math::max([$limit, 1]), 100]);
497→  LET $project_entity_ids = SELECT VALUE `in` FROM belongs_to WHERE out = $project;
498→
499→  LET $task_rows = SELECT
500→    id,
