502→    title AS text,
503→    extraction_confidence AS confidence,
504→    source_message AS sourceMessage,
505→    priority,
506→    created_at
507→  FROM task
508→  WHERE workspace = $workspace
509→    AND extraction_confidence != NONE
510→    AND id IN $project_entity_ids
511→    AND string::contains(string::lowercase(title), $query)
512→  ORDER BY created_at DESC
513→  LIMIT $safe_limit;
514→
515→  LET $decision_rows = SELECT
516→    id,
517→    "decision" AS kind,
518→    summary AS text,
519→    extraction_confidence AS confidence,
520→    source_message AS sourceMessage,
521→    priority,
522→    created_at
523→  FROM decision
524→  WHERE workspace = $workspace
525→    AND extraction_confidence != NONE
526→    AND id IN $project_entity_ids
527→    AND string::contains(string::lowercase(summary), $query)
528→  ORDER BY created_at DESC
529→  LIMIT $safe_limit;
530→
531→  LET $question_rows = SELECT
532→    id,
533→    "question" AS kind,
534→    text AS text,
535→    extraction_confidence AS confidence,
536→    source_message AS sourceMessage,
537→    priority,
538→    created_at
539→  FROM question
540→  WHERE workspace = $workspace
541→    AND extraction_confidence != NONE
