550→DEFINE FUNCTION fn::conversation_recent($conversation: record<conversation>, $limit: int) {
551→  LET $safe_limit = math::min([math::max([$limit, 1]), 50]);
552→  RETURN SELECT id, role, text, createdAt
553→  FROM message
554→  WHERE conversation = $conversation
555→  ORDER BY createdAt DESC
556→  LIMIT $safe_limit;
