559→DEFINE FUNCTION fn::entity_neighbors($entity: record) {
560→  RETURN SELECT
561→    ->entity_relation->(workspace, project, person, feature, task, decision, question) AS outgoing,
562→    <-entity_relation<-(workspace, project, person, feature, task, decision, question) AS incoming
563→  FROM $entity;
564→};
