 63→/** List active decisions for a project, optionally filtered by area/category */
 64→export async function listProjectDecisions(input: {
 65→  surreal: Surreal;
 66→  workspaceRecord: RecordId<"workspace", string>;
 67→  projectRecord: RecordId<"project", string>;
 68→  area?: string;
 69→}): Promise<{
 70→  confirmed: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 71→  provisional: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 72→  contested: Array<{ id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string }>;
 73→}> {
 74→  const areaFilter = input.area
 75→    ? `AND category = $area`
 76→    : "";
 77→
 78→  const [rows] = await input.surreal
 79→    .query<[DecisionRow[]]>(
 80→      `SELECT id, summary, status, rationale, decided_at, category, priority, created_at
 81→       FROM decision
 82→       WHERE workspace = $workspace
 83→         AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)
 84→         ${areaFilter}
 85→       ORDER BY created_at DESC LIMIT 50;`,
 86→      {
 87→        workspace: input.workspaceRecord,
 88→        project: input.projectRecord,
 89→        ...(input.area ? { area: input.area } : {}),
 90→      },
 91→    )
 92→    .collect<[DecisionRow[]]>();
 93→
 94→  type DecisionItem = { id: string; summary: string; status: string; rationale?: string; decided_at?: string; category?: string };
 95→  const confirmed: DecisionItem[] = [];
 96→  const provisional: DecisionItem[] = [];
 97→  const contested: DecisionItem[] = [];
 98→
 99→  for (const d of rows) {
100→    const item: DecisionItem = {
101→      id: toRawId(d.id),
102→      summary: d.summary,
103→      status: d.status,
104→      ...(d.rationale ? { rationale: d.rationale } : {}),
105→      ...(d.decided_at ? { decided_at: toIso(d.decided_at) } : {}),
106→      ...(d.category ? { category: d.category } : {}),
107→    };
108→
109→    if (d.status === "contested") contested.push(item);
110→    else if (d.status === "provisional" || d.status === "inferred") provisional.push(item);
111→    else if (d.status === "confirmed") confirmed.push(item);
112→  }
113→
114→  return { confirmed, provisional, contested };
115→}
