117→/** Get task dependency tree (recursive) */
118→export async function getTaskDependencyTree(input: {
119→  surreal: Surreal;
120→  workspaceRecord: RecordId<"workspace", string>;
121→  taskRecord: RecordId<"task", string>;
122→}): Promise<{
123→  task: { id: string; title: string; status: string };
124→  dependencies: Array<{ id: string; title: string; status: string; resolved: boolean }>;
125→  dependents: Array<{ id: string; title: string; status: string }>;
126→  subtasks: Array<{ id: string; title: string; status: string }>;
127→}> {
128→  const task = await input.surreal.select<TaskRow>(input.taskRecord);
129→  if (!task) throw new Error(`task not found: ${input.taskRecord.id}`);
130→  if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
131→    throw new Error("task is outside the current workspace scope");
132→  }
133→
134→  const query = `
135→    -- Tasks this task depends on
136→    SELECT id, title, status
137→    FROM task
138→    WHERE id IN (SELECT VALUE out FROM depends_on WHERE \`in\` = $task);
139→
140→    -- Tasks that depend on this task
141→    SELECT id, title, status
142→    FROM task
143→    WHERE id IN (SELECT VALUE \`in\` FROM depends_on WHERE out = $task);
144→
145→    -- Subtasks
146→    SELECT id, title, status
147→    FROM task
148→    WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $task)
149→    ORDER BY created_at ASC;
150→  `;
151→
152→  const results = await input.surreal
153→    .query<[DependencyRow[], DependencyRow[], SubtaskRow[]]>(query, { task: input.taskRecord })
154→    .collect<[DependencyRow[], DependencyRow[], SubtaskRow[]]>();
155→
156→  const [deps, dependents, subtasks] = results;
157→
158→  return {
159→    task: { id: toRawId(task.id), title: task.title, status: task.status },
160→    dependencies: deps.map((d) => ({
161→      id: toRawId(d.id),
162→      title: d.title,
163→      status: d.status,
164→      resolved: d.status === "done" || d.status === "completed",
165→    })),
166→    dependents: dependents.map((d) => ({ id: toRawId(d.id), title: d.title, status: d.status })),
167→    subtasks: subtasks.map((s) => ({ id: toRawId(s.id), title: s.title, status: s.status })),
168→  };
169→}
