171→/** List architecture constraints for a project */
172→export async function listProjectConstraints(input: {
173→  surreal: Surreal;
174→  workspaceRecord: RecordId<"workspace", string>;
175→  projectRecord: RecordId<"project", string>;
176→  area?: string;
177→}): Promise<Array<{ text: string; source: string; severity: "hard" | "soft" }>> {
178→  // Constraints come from two sources:
179→  // 1. Decisions marked as confirmed/contested (hard constraints)
180→  // 2. Observations with severity "conflict" or "warning"
181→
182→  const areaFilter = input.area ? `AND category = $area` : "";
183→
184→  const query = `
185→    LET $project_entity_ids = SELECT VALUE \`in\` FROM belongs_to WHERE out = $project;
186→
187→    SELECT summary AS text, "decision" AS source_type, status, id
188→    FROM decision
189→    WHERE workspace = $workspace
190→      AND id IN $project_entity_ids
191→      AND status IN ["confirmed", "contested"]
192→      ${areaFilter}
193→    ORDER BY created_at DESC LIMIT 30;
194→
195→    SELECT text, "observation" AS source_type, severity, id
196→    FROM observation
197→    WHERE workspace = $workspace
198→      AND status IN ["open", "acknowledged"]
199→      AND severity IN ["conflict", "warning"]
200→    ORDER BY created_at DESC LIMIT 20;
201→  `;
202→
203→  const results = await input.surreal
204→    .query<[null, Array<{ text: string; source_type: string; status: string; id: RecordId }>, Array<{ text: string; source_type: string; severity: string; id: RecordId }>]>(
205→      query,
206→      {
207→        workspace: input.workspaceRecord,
208→        project: input.projectRecord,
209→        ...(input.area ? { area: input.area } : {}),
210→      },
211→    )
212→    .collect<[null, Array<{ text: string; source_type: string; status: string; id: RecordId }>, Array<{ text: string; source_type: string; severity: string; id: RecordId }>]>();
213→
214→  const [, decisionRows, observationRows] = results;
215→
216→  const constraints: Array<{ text: string; source: string; severity: "hard" | "soft" }> = [];
217→
218→  for (const d of decisionRows) {
219→    constraints.push({
220→      text: d.text,
221→      source: `decision:${(d.id as RecordId<string, string>).id as string}`,
222→      severity: d.status === "contested" ? "hard" : "hard",
223→    });
224→  }
225→
226→  for (const o of observationRows) {
227→    constraints.push({
228→      text: o.text,
229→      source: `observation:${(o.id as RecordId<string, string>).id as string}`,
230→      severity: o.severity === "conflict" ? "hard" : "soft",
231→    });
232→  }
233→
234→  return constraints;
235→}
