237→/** List recent changes since a timestamp */
238→export async function listRecentChanges(input: {
239→  surreal: Surreal;
240→  workspaceRecord: RecordId<"workspace", string>;
241→  projectRecord?: RecordId<"project", string>;
242→  since: string;
243→}): Promise<Array<{ entity_type: string; entity_name: string; change_type: string; changed_at: string }>> {
244→  const sinceDate = new Date(input.since);
245→
246→  const projectFilter = input.projectRecord
247→    ? `AND id IN (SELECT VALUE \`in\` FROM belongs_to WHERE out = $project)`
248→    : "";
249→
250→  const query = `
251→    LET $recent_decisions = SELECT "decision" AS entity_type, summary AS entity_name, status AS change_type, updated_at AS changed_at
252→    FROM decision
253→    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
254→    ORDER BY updated_at DESC LIMIT 20;
255→
256→    LET $recent_tasks = SELECT "task" AS entity_type, title AS entity_name, status AS change_type, updated_at AS changed_at
257→    FROM task
258→    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
259→    ORDER BY updated_at DESC LIMIT 20;
260→
261→    LET $recent_questions = SELECT "question" AS entity_type, text AS entity_name, status AS change_type, updated_at AS changed_at
262→    FROM question
263→    WHERE workspace = $workspace ${projectFilter} AND updated_at > $since
264→    ORDER BY updated_at DESC LIMIT 20;
265→
266→    RETURN array::flatten([$recent_decisions, $recent_tasks, $recent_questions]);
267→  `;
268→
269→  const results = await input.surreal
270→    .query<[null, null, null, EntityChangeRow[]]>(query, {
271→      workspace: input.workspaceRecord,
272→      since: sinceDate,
273→      ...(input.projectRecord ? { project: input.projectRecord } : {}),
274→    })
275→    .collect<[null, null, null, EntityChangeRow[]]>();
276→
277→  return (results[3] ?? []).map((r) => ({
278→    entity_type: r.entity_type,
279→    entity_name: r.entity_name,
280→    change_type: r.change_type,
281→    changed_at: toIso(r.changed_at),
282→  }));
