285→/** Create a subtask with semantic dedup */
286→export async function createSubtask(input: {
287→  surreal: Surreal;
288→  parentTaskRecord: RecordId<"task", string>;
289→  title: string;
290→  workspaceRecord: RecordId<"workspace", string>;
291→  category?: string;
292→  rationale?: string;
293→}): Promise<{ task_id: string; parent_task_id: string; already_existed: boolean }> {
294→  // Check for existing similar subtasks (semantic dedup by title)
295→  const normalizedTitle = input.title.toLowerCase().trim();
296→
297→  const [existingRows] = await input.surreal
298→    .query<[SubtaskRow[]]>(
299→      `SELECT id, title, status
300→       FROM task
301→       WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $parent)
302→       ORDER BY created_at ASC;`,
303→      { parent: input.parentTaskRecord },
304→    )
305→    .collect<[SubtaskRow[]]>();
306→
307→  // Simple dedup: check if any existing subtask title is very similar
308→  for (const existing of existingRows) {
309→    const existingNormalized = existing.title.toLowerCase().trim();
310→    if (existingNormalized === normalizedTitle || levenshteinSimilarity(existingNormalized, normalizedTitle) > 0.85) {
311→      return {
312→        task_id: toRawId(existing.id),
313→        parent_task_id: toRawId(input.parentTaskRecord),
314→        already_existed: true,
315→      };
316→    }
317→  }
318→
319→  // Get parent task's category if not specified
320→  const parentTask = await input.surreal.select<TaskRow>(input.parentTaskRecord);
321→  if (!parentTask) throw new Error(`parent task not found: ${input.parentTaskRecord.id}`);
322→  if ((parentTask.workspace.id as string) !== (input.workspaceRecord.id as string)) {
323→    throw new Error("parent task is outside the current workspace scope");
324→  }
325→
326→  const now = new Date();
327→  const taskRecord = new RecordId("task", randomUUID());
328→
329→  await input.surreal.create(taskRecord).content({
330→    title: input.title,
331→    status: "todo",
332→    created_at: now,
333→    updated_at: now,
334→    workspace: input.workspaceRecord,
335→    ...(input.category ? { category: input.category } : parentTask.category ? { category: parentTask.category } : {}),
336→    ...(input.rationale ? { description: input.rationale } : {}),
337→  });
338→
339→  // Create subtask_of edge
340→  await input.surreal
341→    .relate(taskRecord, new RecordId("subtask_of", randomUUID()), input.parentTaskRecord, {
342→      added_at: now,
343→    })
344→    .output("after");
345→
346→  // Copy belongs_to edges from parent (inherit project/feature)
347→  const [parentBelongsTo] = await input.surreal
348→    .query<[Array<{ out: RecordId }>]>(
349→      "SELECT out FROM belongs_to WHERE `in` = $parent;",
350→      { parent: input.parentTaskRecord },
351→    )
352→    .collect<[Array<{ out: RecordId }>]>();
353→
354→  for (const edge of parentBelongsTo) {
355→    await input.surreal
356→      .relate(taskRecord, new RecordId("belongs_to", randomUUID()), edge.out, {
357→        added_at: now,
358→      })
359→      .output("after");
360→  }
361→
362→  return {
363→    task_id: toRawId(taskRecord),
364→    parent_task_id: toRawId(input.parentTaskRecord),
365→    already_existed: false,
366→  };
367→}
