369→/** Update task status with subtask rollup */
370→export async function updateTaskStatus(input: {
371→  surreal: Surreal;
372→  workspaceRecord: RecordId<"workspace", string>;
373→  taskRecord: RecordId<"task", string>;
374→  status: string;
375→  notes?: string;
376→}): Promise<{ task_id: string; status: string; parent_status?: string }> {
377→  const now = new Date();
378→  const task = await input.surreal.select<TaskRow>(input.taskRecord);
379→  if (!task) throw new Error(`task not found: ${input.taskRecord.id}`);
380→  if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
381→    throw new Error("task is outside the current workspace scope");
382→  }
383→
384→  await input.surreal.update(input.taskRecord).merge({
385→    status: input.status,
386→    updated_at: now,
387→  });
388→
389→  if (input.notes) {
390→    // Append note to description_entries
391→    const task = await input.surreal.select<{ description_entries?: Array<{ text: string; created_at: Date }> }>(input.taskRecord);
392→    const entries = task?.description_entries ?? [];
393→    entries.push({ text: input.notes, created_at: now });
394→    await input.surreal.update(input.taskRecord).merge({ description_entries: entries });
395→  }
396→
397→  // Check if this task has a parent (subtask_of) and compute rollup
398→  const [parentRows] = await input.surreal
399→    .query<[Array<{ out: RecordId<"task", string> }>]>(
400→      "SELECT out FROM subtask_of WHERE `in` = $task LIMIT 1;",
401→      { task: input.taskRecord },
402→    )
403→    .collect<[Array<{ out: RecordId<"task", string> }>]>();
404→
405→  let parentStatus: string | undefined;
406→
407→  if (parentRows.length > 0) {
408→    const parentRecord = parentRows[0].out;
409→    parentStatus = await computeSubtaskRollup(input.surreal, parentRecord);
410→  }
411→
412→  return {
413→    task_id: toRawId(input.taskRecord),
414→    status: input.status,
415→    ...(parentStatus ? { parent_status: parentStatus } : {}),
416→  };
417→}
