419→/** Compute and apply subtask rollup on a parent task */
420→async function computeSubtaskRollup(
421→  surreal: Surreal,
422→  parentRecord: RecordId<"task", string>,
423→): Promise<string> {
424→  const [subtaskRows] = await surreal
425→    .query<[SubtaskRow[]]>(
426→      `SELECT id, title, status
427→       FROM task
428→       WHERE id IN (SELECT VALUE \`in\` FROM subtask_of WHERE out = $parent);`,
429→      { parent: parentRecord },
430→    )
431→    .collect<[SubtaskRow[]]>();
432→
433→  if (subtaskRows.length === 0) return "unknown";
434→
435→  const allCompleted = subtaskRows.every((s) => s.status === "done" || s.status === "completed");
436→  const anyBlocked = subtaskRows.some((s) => s.status === "blocked");
437→  const anyInProgress = subtaskRows.some((s) => s.status === "in_progress");
438→  const allTodo = subtaskRows.every((s) => s.status === "todo");
439→
440→  let derivedStatus: string;
441→
442→  if (allCompleted) derivedStatus = "completed";
443→  else if (anyBlocked && anyInProgress) derivedStatus = "in_progress";
444→  else if (anyBlocked) derivedStatus = "blocked";
445→  else if (anyInProgress) derivedStatus = "in_progress";
446→  else if (allTodo) derivedStatus = "todo";
447→  else derivedStatus = "in_progress";
448→
449→  await surreal.update(parentRecord).merge({
450→    status: derivedStatus,
451→    updated_at: new Date(),
452→  });
453→
454→  return derivedStatus;
455→}
