497→  await input.surreal.create(sessionRecord).content({
498→    agent: input.agent,
499→    started_at: now,
500→    workspace: input.workspaceRecord,
501→    project: input.projectRecord,
502→    created_at: now,
503→    ...(input.taskId ? { task_id: new RecordId("task", requireRawId(input.taskId, "task_id")) } : {}),
504→  });
505→
506→  // If task-scoped, link session to task and auto-promote status
507→  if (input.taskId) {
