528→/** End an agent session with summary */
529→export async function endAgentSession(input: {
530→  surreal: Surreal;
531→  workspaceRecord: RecordId<"workspace", string>;
532→  sessionId: string;
533→  summary: string;
534→  decisionsMade?: string[];
535→  questionsAsked?: string[];
536→  tasksProgressed?: Array<{ task_id: string; from_status: string; to_status: string }>;
537→  filesChanged?: Array<{ path: string; change_type: string }>;
538→  observationsLogged?: string[];
539→}): Promise<{ session_id: string; ended: boolean }> {
540→  const now = new Date();
541→  const sessionRecord = new RecordId("agent_session", requireRawId(input.sessionId, "session_id"));
542→  const session = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(sessionRecord);
543→  if (!session) {
544→    throw new Error(`session not found: ${input.sessionId}`);
545→  }
546→  if ((session.workspace.id as string) !== (input.workspaceRecord.id as string)) {
547→    throw new Error("session is outside the current workspace scope");
548→  }
549→
550→  await input.surreal.update(sessionRecord).merge({
551→    ended_at: now,
552→    summary: input.summary,
553→    ...(input.decisionsMade?.length
554→      ? { decisions_made: input.decisionsMade.map((id) => new RecordId("decision", requireRawId(id, "decisions_made[]"))) }
555→      : {}),
556→    ...(input.questionsAsked?.length
557→      ? { questions_asked: input.questionsAsked.map((id) => new RecordId("question", requireRawId(id, "questions_asked[]"))) }
558→      : {}),
559→    ...(input.tasksProgressed?.length
560→      ? {
561→          tasks_progressed: input.tasksProgressed.map((t) => ({
562→            task_id: new RecordId("task", requireRawId(t.task_id, "tasks_progressed[].task_id")),
563→            from_status: t.from_status,
564→            to_status: t.to_status,
565→          })),
566→        }
567→      : {}),
568→    ...(input.filesChanged?.length ? { files_changed: input.filesChanged } : {}),
569→    ...(input.observationsLogged?.length
570→      ? { observations_logged: input.observationsLogged.map((id) => new RecordId("observation", requireRawId(id, "observations_logged[]"))) }
571→      : {}),
572→  });
573→
574→  // Create session -> entity edges
575→  if (input.decisionsMade?.length) {
576→    for (const decisionId of input.decisionsMade) {
577→      const rawDecisionId = requireRawId(decisionId, "decisions_made[]");
578→      await input.surreal
579→        .relate(sessionRecord, new RecordId("produced", randomUUID()), new RecordId("decision", rawDecisionId), {
580→          added_at: now,
581→        })
582→        .output("after");
583→    }
584→  }
585→
586→  if (input.questionsAsked?.length) {
587→    for (const questionId of input.questionsAsked) {
588→      const rawQuestionId = requireRawId(questionId, "questions_asked[]");
589→      await input.surreal
590→        .relate(sessionRecord, new RecordId("asked", randomUUID()), new RecordId("question", rawQuestionId), {
591→          added_at: now,
592→        })
593→        .output("after");
594→    }
595→  }
596→
597→  if (input.tasksProgressed?.length) {
598→    for (const t of input.tasksProgressed) {
599→      const rawTaskId = requireRawId(t.task_id, "tasks_progressed[].task_id");
600→      await input.surreal
601→        .relate(sessionRecord, new RecordId("progressed", randomUUID()), new RecordId("task", rawTaskId), {
602→          from_status: t.from_status,
603→          to_status: t.to_status,
604→          added_at: now,
605→        })
606→        .output("after");
607→    }
608→  }
609→
610→  return { session_id: toRawId(sessionRecord), ended: true };
611→}
