613→/** Log a git commit to the graph */
614→export async function logCommit(input: {
615→  surreal: Surreal;
616→  workspaceRecord: RecordId<"workspace", string>;
617→  projectRecord: RecordId<"project", string>;
618→  sha: string;
619→  message: string;
620→  author: string;
621→  taskUpdates?: Array<{ task_id: string; new_status: string }>;
622→  relatedTaskIds?: string[];
623→  decisionsDetected?: Array<{ name: string; rationale: string }>;
624→}): Promise<{ commit_id: string; tasks_updated: number; tasks_linked: number; decisions_created: number }> {
625→  const now = new Date();
626→  const commitRecord = new RecordId("git_commit", randomUUID());
627→
628→  await input.surreal.create(commitRecord).content({
629→    sha: input.sha,
630→    message: input.message,
631→    author_name: input.author,
632→    workspace: input.workspaceRecord,
633→    authored_at: now,
634→    created_at: now,
635→  });
636→
637→  // Update task statuses
638→  let tasksUpdated = 0;
639→  if (input.taskUpdates?.length) {
640→    for (const update of input.taskUpdates) {
641→      const taskRecord = new RecordId("task", requireRawId(update.task_id, "task_updates[].task_id"));
642→      const task = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(taskRecord);
643→      if (!task) {
644→        throw new Error(`task not found: ${update.task_id}`);
645→      }
646→      if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
647→        throw new Error("task update is outside the current workspace scope");
648→      }
649→      await input.surreal.update(taskRecord).merge({
650→        status: update.new_status,
651→        updated_at: now,
652→      });
653→      tasksUpdated++;
654→    }
655→  }
656→
657→  // Link related tasks to this commit
658→  const linkedTaskIds = new Set<string>();
659→  // Include tasks from task_updates
660→  if (input.taskUpdates?.length) {
661→    for (const update of input.taskUpdates) {
662→      linkedTaskIds.add(requireRawId(update.task_id, "task_updates[].task_id"));
663→    }
664→  }
665→  // Include explicitly declared related tasks
666→  if (input.relatedTaskIds?.length) {
667→    for (const taskId of input.relatedTaskIds) {
668→      linkedTaskIds.add(requireRawId(taskId, "related_task_ids[]"));
669→    }
670→  }
671→  for (const taskId of linkedTaskIds) {
672→    const taskRecord = new RecordId("task", taskId);
673→    const task = await input.surreal.select<{ workspace: RecordId<"workspace", string> }>(taskRecord);
674→    if (!task) {
675→      throw new Error(`task not found: ${taskId}`);
676→    }
677→    if ((task.workspace.id as string) !== (input.workspaceRecord.id as string)) {
678→      throw new Error("task link is outside the current workspace scope");
679→    }
680→    await input.surreal
681→      .relate(taskRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
682→        commit_sha: input.sha,
683→        linked_at: now,
684→      })
685→      .output("after");
686→  }
687→
688→  // Create provisional decisions if flagged
689→  let decisionsCreated = 0;
690→  if (input.decisionsDetected?.length) {
691→    for (const decision of input.decisionsDetected) {
692→      const decisionRecord = new RecordId("decision", randomUUID());
693→      await input.surreal.create(decisionRecord).content({
694→        summary: decision.name,
695→        rationale: decision.rationale,
696→        status: "provisional",
697→        decided_by_name: "code-agent",
698→        workspace: input.workspaceRecord,
699→        source_commit: commitRecord,
700→        created_at: now,
701→        updated_at: now,
702→      });
703→
704→      // Link decision to project
705→      await input.surreal
706→        .relate(decisionRecord, new RecordId("belongs_to", randomUUID()), input.projectRecord, {
707→          added_at: now,
708→        })
709→        .output("after");
710→
711→      // Create implemented_by edge
712→      await input.surreal
713→        .relate(decisionRecord, new RecordId("implemented_by", randomUUID()), commitRecord, {
714→          commit_sha: input.sha,
715→          linked_at: now,
716→        })
717→        .output("after");
718→
719→      decisionsCreated++;
720→    }
721→  }
722→
723→  return {
724→    commit_id: toRawId(commitRecord),
725→    tasks_updated: tasksUpdated,
726→    tasks_linked: linkedTaskIds.size,
727→    decisions_created: decisionsCreated,
728→  };
729→}
