731→// ---------------------------------------------------------------------------
732→// Utility
733→// ---------------------------------------------------------------------------
734→
735→function levenshteinSimilarity(a: string, b: string): number {
736→  if (a === b) return 1;
737→  const longer = a.length > b.length ? a : b;
738→  const shorter = a.length > b.length ? b : a;
739→  if (longer.length === 0) return 1;
740→
741→  const costs: number[] = [];
742→  for (let i = 0; i <= longer.length; i++) {
743→    let lastValue = i;
744→    for (let j = 0; j <= shorter.length; j++) {
745→      if (i === 0) {
746→        costs[j] = j;
747→      } else if (j > 0) {
748→        let newValue = costs[j - 1];
749→        if (longer.charAt(i - 1) !== shorter.charAt(j - 1)) {
750→          newValue = Math.min(Math.min(newValue, lastValue), costs[j]) + 1;
751→        }
752→        costs[j - 1] = lastValue;
753→        lastValue = newValue;
754→      }
755→    }
756→    if (i > 0) costs[shorter.length] = lastValue;
757→  }
758→
759→  return (longer.length - costs[shorter.length]) / longer.length;
760→}
