 16→export async function createSuggestion(input: {
 17→  surreal: Surreal;
 18→  workspaceRecord: RecordId<"workspace", string>;
 19→  text: string;
 20→  category: SuggestionCategory;
 21→  rationale: string;
 22→  suggestedBy: string;
 23→  confidence: number;
 24→  now: Date;
 25→  sourceMessageRecord?: RecordId<"message", string>;
 26→  sourceSessionRecord?: RecordId<"agent_session", string>;
 27→  targetRecord?: SuggestsForTarget;
 28→  evidenceRecords?: EvidenceTarget[];
 29→  embedding?: number[];
 30→}): Promise<SuggestionRecord> {
 31→  const suggestionRecord = new RecordId("suggestion", randomUUID());
 32→
 33→  await input.surreal.create(suggestionRecord).content({
 34→    text: input.text,
 35→    category: input.category,
 36→    rationale: input.rationale,
 37→    suggested_by: input.suggestedBy,
 38→    confidence: input.confidence,
 39→    status: "pending",
 40→    workspace: input.workspaceRecord,
 41→    ...(input.sourceMessageRecord ? { source_message: input.sourceMessageRecord } : {}),
 42→    ...(input.sourceSessionRecord ? { source_session: input.sourceSessionRecord } : {}),
 43→    ...(input.embedding ? { embedding: input.embedding } : {}),
 44→    created_at: input.now,
 45→    updated_at: input.now,
 46→  });
 47→
 48→  if (input.targetRecord) {
 49→    await input.surreal
 50→      .relate(suggestionRecord, new RecordId("suggests_for", randomUUID()), input.targetRecord, {
 51→        added_at: input.now,
 52→      })
 53→      .output("after");
 54→  }
 55→
 56→  if (input.evidenceRecords) {
 57→    for (const evidenceRecord of input.evidenceRecords) {
 58→      await input.surreal
 59→        .relate(suggestionRecord, new RecordId("suggestion_evidence", randomUUID()), evidenceRecord, {
 60→          added_at: input.now,
 61→        })
 62→        .output("after");
 63→    }
 64→  }
 65→
 66→  return suggestionRecord;
 67→}
