191→type ConvertTargetKind = "task" | "feature" | "decision" | "project";
192→
193→export async function convertSuggestion(input: {
194→  surreal: Surreal;
195→  workspaceRecord: RecordId<"workspace", string>;
196→  suggestionRecord: SuggestionRecord;
197→  targetKind: ConvertTargetKind;
198→  title?: string;
199→  embeddingModel: EmbeddingModel;
200→  embeddingDimension: number;
201→  now: Date;
202→}): Promise<{ entityId: string; table: ConvertTargetKind }> {
203→  // 1. Validate suggestion exists + workspace scope + convertible status
204→  const row = await input.surreal.select<{
205→    workspace: RecordId<"workspace", string>;
206→    text: string;
207→    rationale: string;
208→    category: string;
209→    status: string;
210→  }>(input.suggestionRecord);
211→  if (!row) {
212→    throw new Error(`suggestion not found: ${input.suggestionRecord.id as string}`);
213→  }
214→  if ((row.workspace.id as string) !== (input.workspaceRecord.id as string)) {
215→    throw new Error("suggestion is outside the current workspace scope");
216→  }
217→  if (!["pending", "accepted", "deferred"].includes(row.status)) {
218→    throw new Error(`suggestion cannot be converted from status '${row.status}'`);
219→  }
220→
221→  const entityName = input.title ?? row.text;
222→
223→  // 2. Create embedding
224→  const embedding = await createEmbeddingVector(input.embeddingModel, entityName, input.embeddingDimension);
225→
226→  // 3. Resolve suggests_for target to find linked project
227→  const [suggestsForRows] = await input.surreal
228→    .query<[Array<{ out: RecordId<string, string> }>]>(
229→      "SELECT out FROM suggests_for WHERE in = $suggestion;",
230→      { suggestion: input.suggestionRecord },
231→    )
232→    .collect<[Array<{ out: RecordId<string, string> }>]>();
233→  const linkedProject = suggestsForRows.find((r) => r.out.table.name === "project");
234→
235→  // 4. Create target entity
236→  let targetRecord: RecordId<string, string>;
237→
238→  if (input.targetKind === "task") {
239→    const taskId = randomUUID();
240→    targetRecord = new RecordId("task", taskId);
241→    await input.surreal.create(targetRecord as RecordId<"task", string>).content({
242→      title: entityName,
243→      status: "open",
244→      workspace: input.workspaceRecord,
245→      ...(embedding ? { embedding } : {}),
246→      created_at: input.now,
247→      updated_at: input.now,
248→    });
249→    if (linkedProject) {
250→      try {
251→        await input.surreal
252→          .relate(targetRecord, new RecordId("belongs_to", randomUUID()), linkedProject.out, { added_at: input.now })
253→          .output("after");
254→      } catch { /* best-effort project linking */ }
255→    }
256→  } else if (input.targetKind === "feature") {
257→    const featureId = randomUUID();
258→    targetRecord = new RecordId("feature", featureId);
259→    await input.surreal.create(targetRecord as RecordId<"feature", string>).content({
260→      name: entityName,
261→      status: "active",
262→      ...(embedding ? { embedding } : {}),
263→      created_at: input.now,
264→      updated_at: input.now,
265→    });
266→    if (linkedProject) {
267→      try {
268→        await ensureProjectFeatureEdge(
269→          input.surreal,
270→          linkedProject.out as RecordId<"project", string>,
271→          targetRecord as RecordId<"feature", string>,
272→          input.now,
273→        );
274→      } catch { /* best-effort project linking */ }
275→    }
276→  } else if (input.targetKind === "decision") {
277→    const decisionId = randomUUID();
278→    targetRecord = new RecordId("decision", decisionId);
279→    await input.surreal.create(targetRecord as RecordId<"decision", string>).content({
280→      summary: entityName,
281→      status: "proposed",
282→      workspace: input.workspaceRecord,
283→      ...(embedding ? { embedding } : {}),
284→      created_at: input.now,
285→      updated_at: input.now,
286→    });
287→    if (linkedProject) {
288→      try {
289→        await input.surreal
290→          .relate(targetRecord, new RecordId("belongs_to", randomUUID()), linkedProject.out, { added_at: input.now })
291→          .output("after");
292→      } catch { /* best-effort project linking */ }
293→    }
294→  } else {
295→    // project
296→    const projectRecord = await createProjectRecord({
297→      surreal: input.surreal,
298→      name: entityName,
299→      status: "active",
300→      now: input.now,
301→      workspaceRecord: input.workspaceRecord,
302→    });
303→    if (embedding) {
304→      await input.surreal.update(projectRecord).merge({ embedding });
305→    }
306→    targetRecord = projectRecord;
307→  }
308→
309→  // 5. Update suggestion to converted
310→  await input.surreal.update(input.suggestionRecord).merge({
311→    status: "converted" satisfies SuggestionStatus,
312→    converted_to: targetRecord,
313→    converted_at: input.now,
314→    updated_at: input.now,
315→  });
316→
317→  // 6. Create converted_from edge: target -> suggestion
318→  await input.surreal
319→    .relate(targetRecord, new RecordId("converted_from", randomUUID()), input.suggestionRecord, {
320→      converted_at: input.now,
321→    })
322→    .output("after");
323→
324→  // 7. Seed description with rationale (fire-and-forget)
325→  void seedDescriptionEntry({
326→    surreal: input.surreal,
327→    targetRecord,
328→    text: row.rationale,
329→  }).catch(() => undefined);
330→
331→  return {
332→    entityId: `${input.targetKind}:${targetRecord.id as string}`,
333→    table: input.targetKind,
334→  };
335→}
