 1→import { tool } from "ai";
 2→import { z } from "zod";
 3→import { SUGGESTION_CATEGORIES } from "../../../shared/contracts";
 4→import { createEmbeddingVector } from "../../graph/embeddings";
 5→import { isEntityInWorkspace, parseRecordIdString } from "../../graph/queries";
 6→import { createSuggestion } from "../../suggestion/queries";
 7→import { requireToolContext } from "./helpers";
 8→import type { ChatToolDeps } from "./types";
 9→
10→export function createCreateSuggestionTool(deps: ChatToolDeps) {
11→  return tool({
12→    description:
13→      "Create a suggestion for the user — a proactive, actionable proposal with rationale. Use when you identify optimizations, risks, opportunities, conflicts, missing elements, or potential pivots that the user should consider. Observations are for agent-to-agent signals; suggestions are agent-to-human proposals.",
14→    inputSchema: z.object({
15→      text: z.string().min(1).describe("The suggestion itself — what you propose the user should consider or do"),
16→      category: z
17→        .enum(SUGGESTION_CATEGORIES)
18→        .describe(
19→          "optimization: improve existing approach. risk: potential problem to address. opportunity: beneficial possibility. conflict: contradictory elements detected. missing: gap in current plan. pivot: fundamental direction change worth considering.",
20→        ),
21→      rationale: z.string().min(1).describe("Why you are making this suggestion — the reasoning and evidence behind it"),
22→      confidence: z.number().min(0).max(1).describe("How confident you are in this suggestion (0-1)"),
23→      target_entity_id: z
24→        .string()
25→        .optional()
26→        .describe("Optional target entity this suggestion is about (format: table:id, e.g. project:uuid or feature:uuid)"),
27→      evidence_entity_ids: z
28→        .array(z.string())
29→        .optional()
30→        .describe("Optional entity IDs that support the rationale (format: table:id). Can include observations, decisions, tasks, etc."),
31→    }),
32→    execute: async (input, options) => {
33→      const context = requireToolContext(options);
34→
35→      const targetTables = ["project", "feature", "task", "question", "decision"] as const;
36→      const targetRecord = input.target_entity_id
37→        ? parseRecordIdString(input.target_entity_id, [...targetTables])
38→        : undefined;
39→
40→      if (targetRecord) {
41→        const scoped = await isEntityInWorkspace(deps.surreal, context.workspaceRecord, targetRecord);
42→        if (!scoped) {
43→          throw new Error("target entity is outside the current workspace scope");
44→        }
45→      }
46→
47→      const evidenceTables = ["workspace", "project", "person", "feature", "task", "decision", "question", "observation"] as const;
48→      const evidenceRecords = input.evidence_entity_ids?.map((id) =>
49→        parseRecordIdString(id, [...evidenceTables]),
50→      );
51→
52→      const embedding = await createEmbeddingVector(deps.embeddingModel, input.text, deps.embeddingDimension);
53→      if (!embedding) {
54→        throw new Error("failed to create embedding for create_suggestion");
55→      }
56→
57→      const suggestionRecord = await createSuggestion({
58→        surreal: deps.surreal,
59→        workspaceRecord: context.workspaceRecord,
60→        text: input.text,
61→        category: input.category,
62→        rationale: input.rationale,
63→        suggestedBy: context.actor,
64→        confidence: input.confidence,
65→        now: new Date(),
66→        sourceMessageRecord: context.currentMessageRecord,
67→        ...(targetRecord ? { targetRecord } : {}),
68→        ...(evidenceRecords ? { evidenceRecords } : {}),
69→        embedding,
70→      });
71→
72→      return {
73→        suggestion_id: `suggestion:${suggestionRecord.id as string}`,
74→        text: input.text,
75→        category: input.category,
76→        rationale: input.rationale,
77→        confidence: input.confidence,
78→        status: "pending",
79→        ...(input.target_entity_id ? { target: input.target_entity_id } : {}),
80→      };
81→    },
82→  });
83→}
