162→  /** POST /api/mcp/:workspaceId/context — Get project context (broad or task-scoped) */
163→  async function handleGetContext(workspaceId: string, request: Request): Promise<Response> {
164→    const auth = await requireAuth(request, workspaceId);
165→    if (auth instanceof Response) return auth;
166→
167→    const body = await parseJsonBody<{ project_id: string; task_id?: string; since?: string; session_id?: string }>(request);
168→    if (body instanceof Response) return body;
169→    if (!body.project_id) return jsonError("project_id is required", 400);
170→    let projectId: string;
171→    let taskId: string | undefined;
172→    let sessionId: string | undefined;
173→    try {
174→      projectId = requireRawId(body.project_id, "project_id");
175→      taskId = body.task_id ? requireRawId(body.task_id, "task_id") : undefined;
176→      sessionId = body.session_id ? requireRawId(body.session_id, "session_id") : undefined;
177→    } catch (error) {
178→      return jsonError(error instanceof Error ? error.message : "invalid id format", 400);
179→    }
180→
181→    const projectRecord = new RecordId("project", projectId);
182→    const scopedProjectError = await requireScopedRecord(projectRecord, auth.workspaceRecord, "project");
183→    if (scopedProjectError) return scopedProjectError;
184→    if (taskId) {
185→      const scopedTaskError = await requireScopedRecord(new RecordId("task", taskId), auth.workspaceRecord, "task");
186→      if (scopedTaskError) return scopedTaskError;
187→    }
188→    const project = await surreal.select<ProjectRow>(projectRecord);
189→    if (!project) return jsonError("project not found", 404);
190→
191→    try {
192→      const contextPacket = await buildProjectContext({
193→        surreal,
194→        workspaceRecord: auth.workspaceRecord,
195→        workspaceName: auth.workspaceName,
196→        projectRecord,
197→        ...(taskId ? { taskId } : {}),
198→        since: body.since,
199→        ...(sessionId ? { excludeSessionId: sessionId } : {}),
200→      });
201→
202→      logInfo("mcp.context.built", "MCP context packet assembled", {
203→        workspaceId,
204→        projectId,
205→        taskId,
206→        decisionsCount:
207→          contextPacket.decisions.confirmed.length +
208→          contextPacket.decisions.provisional.length +
209→          contextPacket.decisions.contested.length,
210→        tasksCount: contextPacket.active_tasks.length,
211→      });
212→
213→      return jsonResponse(contextPacket, 200);
214→    } catch (error) {
215→      logError("mcp.context.failed", "Failed to build MCP context", error);
216→      return jsonError("failed to build context", 500);
217→    }
218→  }
