830→    if (!body.project_id) return jsonError("project_id is required", 400);
831→    let projectId: string;
832→    let taskId: string | undefined;
833→    try {
834→      projectId = requireRawId(body.project_id, "project_id");
835→      taskId = body.task_id ? requireRawId(body.task_id, "task_id") : undefined;
836→    } catch (error) {
837→      return jsonError(error instanceof Error ? error.message : "invalid id", 400);
838→    }
