843→      const scopedTaskError = await requireScopedRecord(new RecordId("task", taskId), auth.workspaceRecord, "task");
844→      if (scopedTaskError) return scopedTaskError;
845→    }
846→    const result = await createAgentSession({
847→      surreal,
848→      agent: body.agent,
849→      workspaceRecord: auth.workspaceRecord,
850→      projectRecord,
851→      ...(taskId ? { taskId } : {}),
