873→    if (!body.summary) return jsonError("summary is required", 400);
874→    try {
875→      requireRawId(body.session_id, "session_id");
876→      for (const id of body.decisions_made ?? []) requireRawId(id, "decisions_made[]");
877→      for (const id of body.questions_asked ?? []) requireRawId(id, "questions_asked[]");
