 20→export function createEntityActionsHandler(
 21→  deps: ServerDependencies,
 22→): (entityId: string, request: Request) => Promise<Response> {
 23→  return (entityId: string, request: Request) => handleEntityAction(deps, entityId, request);
 24→}
 25→
 26→async function handleEntityAction(
 27→  deps: ServerDependencies,
 28→  entityId: string,
 29→  request: Request,
 30→): Promise<Response> {
 31→  let body: EntityActionRequest;
 32→  try {
 33→    body = await request.json() as EntityActionRequest;
 34→  } catch {
 35→    return jsonError("invalid JSON body", 400);
 36→  }
 37→
 38→  if (!body.action || !["confirm", "override", "complete", "set_priority", "acknowledge", "resolve", "dismiss", "accept", "defer", "convert"].includes(body.action)) {
 39→    return jsonError("action must be one of: confirm, override, complete, set_priority, acknowledge, resolve, dismiss, accept, defer, convert", 400);
 40→  }
 41→
 42→  const url = new URL(request.url);
 43→  const workspaceId = url.searchParams.get("workspaceId")?.trim();
 44→  if (!workspaceId) {
 45→    return jsonError("workspaceId is required", 400);
 46→  }
 47→
 48→  let workspaceRecord;
 49→  try {
 50→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 51→  } catch (error) {
 52→    if (error instanceof HttpError) {
 53→      return jsonError(error.message, error.status);
 54→    }
 55→    logError("entity.action.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
 56→    return jsonError("failed to resolve workspace", 500);
 57→  }
 58→
 59→  try {
 60→    const entityTables: EntityActionTable[] = ["workspace", "project", "person", "feature", "task", "decision", "question", "observation", "suggestion"];
 61→    const entityRecord = parseRecordIdString(entityId, entityTables);
 62→
 63→    const table = entityRecord.table.name;
 64→    const now = new Date();
 65→
 66→    // Observation actions have separate handlers from task/decision/question.
 67→    if (table === "observation") {
 68→      if (body.action === "acknowledge") {
 69→        await acknowledgeObservation({
 70→          surreal: deps.surreal,
 71→          workspaceRecord,
 72→          observationRecord: entityRecord as RecordId<"observation", string>,
 73→          now,
 74→        });
 75→        logInfo("entity.action.acknowledge", "Observation acknowledged", { workspaceId, entityId });
 76→        return jsonResponse({ status: "acknowledged" }, 200);
 77→      }
 78→
 79→      if (body.action === "resolve") {
 80→        await resolveObservation({
 81→          surreal: deps.surreal,
 82→          workspaceRecord,
 83→          observationRecord: entityRecord as RecordId<"observation", string>,
 84→          now,
 85→        });
 86→        logInfo("entity.action.resolve", "Observation resolved", { workspaceId, entityId });
 87→        return jsonResponse({ status: "resolved" }, 200);
 88→      }
 89→
 90→      return jsonError(`action '${body.action}' is not valid for entity type 'observation'`, 400);
 91→    }
 92→
 93→    // Suggestion actions handle their own workspace validation internally.
 94→    if (table === "suggestion") {
 95→      if (body.action === "accept") {
 96→        await acceptSuggestion({
 97→          surreal: deps.surreal,
 98→          workspaceRecord,
 99→          suggestionRecord: entityRecord as RecordId<"suggestion", string>,
100→          now,
101→        });
102→        logInfo("entity.action.accept", "Suggestion accepted", { workspaceId, entityId });
103→        return jsonResponse({ status: "accepted" }, 200);
104→      }
105→
106→      if (body.action === "dismiss") {
107→        await dismissSuggestion({
108→          surreal: deps.surreal,
109→          workspaceRecord,
110→          suggestionRecord: entityRecord as RecordId<"suggestion", string>,
111→          now,
112→        });
113→        logInfo("entity.action.dismiss", "Suggestion dismissed", { workspaceId, entityId });
114→        return jsonResponse({ status: "dismissed" }, 200);
115→      }
116→
117→      if (body.action === "defer") {
118→        await deferSuggestion({
119→          surreal: deps.surreal,
120→          workspaceRecord,
121→          suggestionRecord: entityRecord as RecordId<"suggestion", string>,
122→          now,
123→        });
124→        logInfo("entity.action.defer", "Suggestion deferred", { workspaceId, entityId });
125→        return jsonResponse({ status: "deferred" }, 200);
126→      }
127→
128→      if (body.action === "convert") {
129→        if (!body.convertTo || !["task", "feature", "decision", "project"].includes(body.convertTo)) {
130→          return jsonError("convertTo must be one of: task, feature, decision, project", 400);
131→        }
132→        const result = await convertSuggestion({
133→          surreal: deps.surreal,
134→          workspaceRecord,
135→          suggestionRecord: entityRecord as RecordId<"suggestion", string>,
136→          targetKind: body.convertTo as "task" | "feature" | "decision" | "project",
137→          title: body.convertTitle,
138→          embeddingModel: deps.embeddingModel,
139→          embeddingDimension: deps.config.embeddingDimension,
140→          now,
141→        });
142→        logInfo("entity.action.convert", "Suggestion converted", { workspaceId, suggestionId: entityId, convertedEntityId: result.entityId, table: result.table });
143→        return jsonResponse({ status: "converted", entityId: result.entityId, table: result.table }, 201);
144→      }
145→
146→      return jsonError(`action '${body.action}' is not valid for entity type 'suggestion'`, 400);
147→    }
148→
149→    const scoped = await isEntityInWorkspace(deps.surreal, workspaceRecord, entityRecord as RecordId<GraphEntityTable, string>);
150→    if (!scoped) {
151→      return jsonError("entity is outside the current workspace scope", 403);
152→    }
153→
154→    if (body.action === "confirm" && table === "decision") {
155→      const [decisionRows] = await deps.surreal
156→        .query<[Array<{ summary: string }>]>(
157→          "SELECT summary FROM $record LIMIT 1;",
158→          { record: entityRecord },
159→        )
160→        .collect<[Array<{ summary: string }>]>();
161→      const decisionSummary = decisionRows[0]?.summary ?? entityId;
162→
163→      await confirmDecisionRecord({
164→        surreal: deps.surreal,
165→        decisionRecord: entityRecord as RecordId<"decision", string>,
166→        confirmedAt: now,
167→        notes: body.notes,
168→      });
169→
170→      void fireDescriptionUpdates({
171→        surreal: deps.surreal,
172→        extractionModel: deps.extractionModel,
173→        trigger: {
174→          kind: "decision_confirmed",
175→          entity: entityRecord,
176→          summary: `Decision confirmed: ${decisionSummary}`,
177→        },
178→      }).catch(() => undefined);
179→
180→      logInfo("entity.action.confirm", "Decision confirmed", { workspaceId, entityId });
181→      return jsonResponse({ status: "confirmed" }, 200);
182→    }
183→
184→    if (body.action === "override" && table === "decision") {
185→      if (!body.newSummary) {
186→        return jsonError("newSummary is required for override action", 400);
187→      }
188→      await deps.surreal.update(entityRecord as RecordId<"decision", string>).merge({
189→        summary: body.newSummary,
190→        status: "overridden",
191→        updated_at: now,
192→        ...(body.notes ? { override_notes: body.notes } : {}),
193→      });
194→      logInfo("entity.action.override", "Decision overridden", { workspaceId, entityId });
195→      return jsonResponse({ status: "overridden" }, 200);
196→    }
197→
198→    if (body.action === "complete" && table === "feature") {
199→      const [featureRows] = await deps.surreal
200→        .query<[Array<{ name: string }>]>(
201→          "SELECT name FROM $record LIMIT 1;",
202→          { record: entityRecord },
203→        )
204→        .collect<[Array<{ name: string }>]>();
205→      const featureName = featureRows[0]?.name ?? entityId;
206→
207→      await deps.surreal.update(entityRecord as RecordId<"feature", string>).merge({
208→        status: "done",
209→        updated_at: now,
210→      });
211→
212→      void fireDescriptionUpdates({
213→        surreal: deps.surreal,
214→        extractionModel: deps.extractionModel,
215→        trigger: {
216→          kind: "feature_completed",
217→          entity: entityRecord,
218→          summary: `Feature completed: ${featureName}`,
219→        },
220→      }).catch(() => undefined);
221→
222→      logInfo("entity.action.complete", "Feature completed", { workspaceId, entityId });
223→      return jsonResponse({ status: "completed" }, 200);
224→    }
225→
226→    if (body.action === "complete" && table === "task") {
227→      const [taskRows] = await deps.surreal
228→        .query<[Array<{ title: string }>]>(
229→          "SELECT title FROM $record LIMIT 1;",
230→          { record: entityRecord },
231→        )
232→        .collect<[Array<{ title: string }>]>();
233→      const taskTitle = taskRows[0]?.title ?? entityId;
234→
235→      await deps.surreal.update(entityRecord as RecordId<"task", string>).merge({
236→        status: "done",
237→        completed_at: now,
238→        updated_at: now,
239→      });
240→
241→      void fireDescriptionUpdates({
242→        surreal: deps.surreal,
243→        extractionModel: deps.extractionModel,
244→        trigger: {
245→          kind: "task_completed",
246→          entity: entityRecord,
247→          summary: `Task completed: ${taskTitle}`,
248→        },
249→      }).catch(() => undefined);
250→
251→      logInfo("entity.action.complete", "Task completed", { workspaceId, entityId });
252→      return jsonResponse({ status: "completed" }, 200);
253→    }
254→
255→    if (body.action === "dismiss" && table === "question") {
256→      await deps.surreal.update(entityRecord as RecordId<"question", string>).merge({
257→        status: "dismissed",
258→        updated_at: now,
259→      });
260→      logInfo("entity.action.dismiss", "Question dismissed", { workspaceId, entityId });
261→      return jsonResponse({ status: "dismissed" }, 200);
262→    }
263→
264→    if (body.action === "set_priority" && (table === "task" || table === "decision" || table === "question")) {
265→      if (!body.priority || !(ENTITY_PRIORITIES as readonly string[]).includes(body.priority)) {
266→        return jsonError("priority must be one of: low, medium, high, critical", 400);
267→      }
268→      await deps.surreal.update(entityRecord).merge({
269→        priority: body.priority,
270→        updated_at: now,
271→      });
272→      logInfo("entity.action.set_priority", "Priority updated", { workspaceId, entityId, priority: body.priority });
273→      return jsonResponse({ status: "priority_updated", priority: body.priority }, 200);
274→    }
275→
276→    return jsonError(`action '${body.action}' is not valid for entity type '${table}'`, 400);
277→  } catch (error) {
278→    logError("entity.action.failed", "Entity action failed", error, {
279→      workspaceId,
280→      entityId,
281→      action: body.action,
282→    });
283→    const message = error instanceof Error ? error.message : "entity action failed";
284→    return jsonError(message, 500);
285→  }
286→}
