187→  if (recentDecisions.length === 0) {
188→    lines.push("- Decisions: none");
189→  } else {
190→    const statusCounts = new Map<string, number>();
191→    for (const d of recentDecisions) {
192→      statusCounts.set(d.status, (statusCounts.get(d.status) ?? 0) + 1);
193→    }
194→    const breakdown = [...statusCounts.entries()].map(([s, c]) => `${c} ${s}`).join(", ");
195→    lines.push(`- Decisions: ${recentDecisions.length} (${breakdown})`);
196→  }
197→
198→  // Questions: just count
199→  lines.push(`- Open questions: ${openQuestions.length}`);
200→
201→  // Observations: count by severity
202→  if (openObservations.length === 0) {
203→    lines.push("- Observations: none");
204→  } else {
205→    const severityCounts = new Map<string, number>();
206→    for (const o of openObservations) {
207→      severityCounts.set(o.severity, (severityCounts.get(o.severity) ?? 0) + 1);
208→    }
209→    const breakdown = [...severityCounts.entries()].map(([s, c]) => `${c} ${s}`).join(", ");
210→    lines.push(`- Observations: ${openObservations.length} (${breakdown})`);
211→  }
212→
213→  // Suggestions: count by category
214→  if (pendingSuggestions.length === 0) {
215→    lines.push("- Suggestions: none");
216→  } else {
217→    const categoryCounts = new Map<string, number>();
218→    for (const s of pendingSuggestions) {
219→      categoryCounts.set(s.category, (categoryCounts.get(s.category) ?? 0) + 1);
220→    }
221→    const breakdown = [...categoryCounts.entries()].map(([c, n]) => `${n} ${c}`).join(", ");
222→    lines.push(`- Suggestions: ${pendingSuggestions.length} (${breakdown})`);
223→  }
224→
225→  return lines.join("\n");
226→}
