 5→/**
 6→ * brain check-commit
 7→ * Called by pre-commit git hook.
 8→ * Reads staged diff and checks for task completion, unlogged decisions, constraint violations.
 9→ */
10→export async function runCheckCommit(): Promise<void> {
11→  const config = requireConfig();
12→  const client = new BrainHttpClient(config);
13→  const cwd = process.cwd();
14→  const cached = getDirCacheEntry(cwd);
15→
16→  if (!cached) return; // No project mapped — skip silently
17→
18→  let diff: string;
19→  let commitMessage: string;
20→  try {
21→    diff = execSync("git diff --cached", { encoding: "utf-8", cwd }).trim();
22→    try {
23→      commitMessage = execSync("cat .git/COMMIT_EDITMSG", { encoding: "utf-8", cwd }).trim();
24→    } catch {
25→      commitMessage = "";
26→    }
27→  } catch {
28→    return; // Not in a git repo or no staged changes
29→  }
30→
31→  if (!diff) return;
32→
33→  try {
34→    // Truncate for token budget
35→    const truncatedDiff = diff.length > 8000 ? diff.slice(0, 8000) : diff;
36→
37→    const result = await client.checkCommit({
38→      project_id: cached.project_id,
39→      diff: truncatedDiff,
40→      commit_message: commitMessage,
41→    });
42→
43→    // Display findings to stderr (stdout is reserved for git hook protocol)
44→    for (const tc of result.task_completions) {
45→      if (tc.confidence >= 0.6) {
46→        process.stderr.write(`Brain: This commit may complete: ${tc.task_title}\n`);
47→      }
48→    }
49→    for (const d of result.unlogged_decisions) {
50→      process.stderr.write(`Brain: Unlogged decision: ${d.description}\n`);
51→    }
52→    for (const v of result.constraint_violations) {
53→      process.stderr.write(`Brain: Constraint violation (${v.severity}): ${v.violation}\n`);
54→    }
55→  } catch {
56→    // Never block commits on analysis failures
57→  }
58→}
